DO $seed$ DECLARE
  _ege_kinematics UUID;
  _egor_id UUID;
  _drafts_folder_id UUID;
BEGIN

SELECT id INTO _egor_id
FROM auth.users
WHERE email = 'egor.o.blinov@gmail.com'
LIMIT 1;

IF _egor_id IS NULL THEN
  RAISE NOTICE 'User egor.o.blinov@gmail.com not found — skipping seed';
  RETURN;
END IF;

SELECT id INTO _drafts_folder_id
FROM public.kb_folders
WHERE owner_id = _egor_id AND name = 'Черновики для сократа' AND parent_id IS NULL
LIMIT 1;

IF _drafts_folder_id IS NULL THEN
  RAISE NOTICE 'Folder "Черновики для сократа" not found — skipping seed';
  RETURN;
END IF;

SELECT id INTO _ege_kinematics
FROM public.kb_topics
WHERE name = 'Кинематика' AND exam = 'ege'
LIMIT 1;

IF _ege_kinematics IS NULL THEN
  RAISE NOTICE 'Topic Кинематика (ege) not found — skipping seed';
  RETURN;
END IF;

-- ЗАДАНИЕ 1 — КИМ №1 (32 задачи)

-- ЗАДАНИЕ 22 — КИМ №22 (14 задач)

-- ТЕМАТИЧЕСКИЙ КОНТРОЛЬ 2 (8 задач)

END $seed$;