INSERT INTO public.kb_tasks (folder_id, owner_id, exam, kim_number, text, answer, solution, answer_format, source_label, attachment_url) VALUES
(_drafts_folder_id, _egor_id, 'ege', 1, 'На рисунке представлен график зависимости пути $S$ велосипедиста от времени $t$. Определите скорость велосипедиста в интервале времени от 50 до 70 с.', '7,5 м/с', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_01.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На рисунке представлен график зависимости пути $S$, пройденного материальной точкой, от времени $t$. Определите скорость материальной точки в интервале времени от 1 до 3 с.', '2,5 м/с', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_02.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На рисунке представлен график зависимости пути $S$, пройденного материальной точкой, от времени $t$. Определите скорость материальной точки в интервале времени от 5 до 7 с.', '5 м/с', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_03.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На рисунке представлен график зависимости координаты $x$ велосипедиста от времени $t$. Определите проекцию $v_x$ скорости велосипедиста в интервале времени от 30 до 50 с.', '5 м/с', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_04.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На рисунке представлен график зависимости координаты $x$ велосипедиста от времени $t$. Определите проекцию $v_x$ скорости велосипедиста в интервале времени от 30 до 50 с.', '-5 м/с', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_05.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На рисунке представлены графики зависимости пройденного пути от времени для двух тел. Определите, во сколько раз скорость второго тела $v_2$ больше скорости первого тела $v_1$.', '1,5', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_06.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На рисунке представлен график движения автобуса из пункта А в пункт Б и обратно. Пункт А находится в точке $x = 0$, а пункт Б — в точке $x = 30$ км. Чему равна скорость автобуса на пути из Б в А?', '50 км/ч', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_07.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'Из двух городов навстречу друг другу с постоянной скоростью движутся два автомобиля. На графике показано изменение расстояния между автомобилями с течением времени. Какова скорость первого автомобиля в системе отсчёта, связанной со вторым автомобилем?', '25 м/с', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_08.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На рисунке приведён график зависимости проекции $v_x$ скорости тела от времени $t$. Определите проекцию $a_x$ ускорения этого тела в интервале времени от 0 до 10 с.', '2 м/с²', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_09.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На рисунке приведён график зависимости проекции $v_x$ скорости тела от времени $t$. Определите проекцию $a_x$ ускорения этого тела в интервале времени от 5 до 10 с.', '-5 м/с²', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_10.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На графике представлена зависимость скорости $v$ прямолинейно движущегося тела от времени $t$. Определите ускорение тела.', '6 м/с²', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_11.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'Используя график зависимости модуля скорости от времени (см. рисунок), определите ускорение прямолинейно движущегося тела в момент времени $t = 1$ с.', '7,5 м/с²', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_12.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На графике приведена зависимость проекции $v_x$ скорости тела от времени $t$ при прямолинейном движении по оси Ох. Определите проекцию $a_x$ ускорения тела.', '-10 м/с²', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_13.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На графике приведена зависимость проекции $v_x$ скорости тела от времени $t$ при прямолинейном движении по оси Ох. Определите проекцию $a_x$ ускорения тела.', '8 м/с²', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_14.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На рисунке показан график зависимости проекции $v_x$ скорости тела от времени $t$. Какова проекция $a_x$ ускорения этого тела в момент времени 2,4 с?', '16 м/с²', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_15.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'Автомобиль движется по прямой улице. На графике представлена зависимость скорости автомобиля от времени. Определите модуль минимального ускорения автомобиля за время наблюдения.', '1 м/с²', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_16.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'Автомобиль движется по прямой улице. На графике представлена зависимость скорости автомобиля от времени. Определите модуль максимального ускорения автомобиля за время наблюдения.', '2 м/с²', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_17.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На графике представлена зависимость скорости автомобиля от времени. Определите путь, пройденный автомобилем в течение интервала времени от 0 до 10 с.', '100 м', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_18.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На графике представлена зависимость скорости автомобиля от времени. Определите путь, пройденный автомобилем в течение интервала времени от 20 до 40 с.', '225 м', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_19.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На графике представлена зависимость скорости автомобиля от времени. Определите путь, пройденный автомобилем за 20 с от момента начала наблюдения.', '350 м', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_20.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На графике представлена зависимость скорости автомобиля от времени. Определите путь, пройденный автомобилем за 30 с от момента начала наблюдения.', '450 м', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_21.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На рисунке представлен график зависимости скорости $v$ автомобиля от времени $t$. Определите по графику путь, пройденный автомобилем в интервале времени от 0 до 3 с.', '25 м', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_22.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'Тело движется вдоль оси Ох. На графике показана зависимость проекции скорости тела на ось Ох от времени. Какой путь, пройденный телом к моменту времени $t = 4$ с?', '6 м', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_23.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На рисунке приведён график зависимости проекции $v_x$ скорости тела, движущегося вдоль оси Ох, от времени. Определите путь, пройденный телом за 10 с от начала наблюдения.', '60 м', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_24.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'Тело движется вдоль оси Ох. По графику зависимости проекции $v_x$ скорости тела от времени $t$ установите модуль перемещения тела за время от $t_1 = 0$ с до $t_2 = 6$ с.', '15 м', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_25.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На рисунке представлен график зависимости скорости $v$ при прямолинейном движении тела от времени $t$. Определите по графику среднюю скорость тела в интервале времени от 0 до 6 с.', '7 м/с', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_26.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'На рисунке представлен график зависимости скорости $v$ тела от времени $t$. Определите среднюю скорость тела в интервале времени от 10 до 50 с.', '7,5 м/с', NULL, 'число', 'demidova_2025', 'storage://kb-attachments/demidova2025/z1_27.svg'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'Координата тела $x$ меняется с течением времени $t$ согласно закону $x = 4 - 2t$, где все величины выражены в СИ. Определите проекцию $v_x$ скорости этого тела.', '−2 м/с', NULL, 'число', 'demidova_2025', NULL),
(_drafts_folder_id, _egor_id, 'ege', 1, 'Координата тела $x$ меняется с течением времени $t$ согласно закону $x = 4t - 6$, где все величины выражены в СИ. Определите проекцию $v_x$ скорости этого тела.', '4 м/с', NULL, 'число', 'demidova_2025', NULL),
(_drafts_folder_id, _egor_id, 'ege', 1, 'Координата тела $x$ меняется с течением времени $t$ согласно закону $x = 4 + 3t - 5t^2$, где все величины выражены в СИ. Определите проекцию $a_x$ ускорения этого тела.', '−10 м/с²', NULL, 'число', 'demidova_2025', NULL),
(_drafts_folder_id, _egor_id, 'ege', 1, 'Координата тела $x$ меняется с течением времени $t$ согласно закону $x = 15 - 5t + 3t^2$, где все величины выражены в СИ. Определите проекцию $a_x$ ускорения этого тела.', '6 м/с²', NULL, 'число', 'demidova_2025', NULL),
(_drafts_folder_id, _egor_id, 'ege', 1, 'Зависимость пути от времени для прямолинейно движущегося тела имеет вид: $s(t) = 2t + 3t^2$, где все величины выражены в СИ. Определите модуль ускорения этого тела.', '6 м/с²', NULL, 'число', 'demidova_2025', NULL);
INSERT INTO public.kb_tasks (folder_id, owner_id, exam, kim_number, text, answer, solution, answer_format, source_label) VALUES
(_drafts_folder_id, _egor_id, 'ege', 22, 'Велосипедист, двигавшийся по прямой со скоростью 5 м/с, начинает разгон с постоянным ускорением, и через 3 с его скорость становится равной 17 м/с. С каким ускорением двигался велосипедист?', '4 м/с²', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 22, 'Автомобиль начал равноускоренное движение по прямой из состояния покоя и закончил ускоряться через 150 м, достигнув скорости 30 м/с. Каково ускорение автомобиля?', '3 м/с²', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 22, 'Начальная скорость самосвала, движущегося прямолинейно и равноускоренно, равна 5 м/с. Его конечная скорость через 10 с равна 15 м/с. Какой путь за это время пройдёт самосвал?', '100 м', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 22, 'За 4 с прямолинейного равноускоренного движения тело прошло 100 м, увеличив свою скорость в 4 раза. Определите начальную скорость тела.', '10 м/с', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 22, 'Мотоциклист, двигавшийся равноускоренно по прямой дороге, на пути 100 м увеличил свою скорость от 0 до 90 км/ч. Сколько времени длился разгон?', '8 с', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 22, 'Поезд, двигаясь со скоростью 30 м/с, начал торможение, и на последнем километре тормозного пути его скорость уменьшалась на 10 м/с. Определите общий тормозной путь поезда, считая его движение равнозамедленным.', '9 км', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 22, 'Камень брошен вертикально вверх. Через 0,5 с после броска его скорость равна 10 м/с. Какова начальная скорость камня? Сопротивлением воздуха пренебречь.', '15 м/с', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 22, 'Сосулька отрывается и падает с крыши дома высотой 25 м. На какой высоте от поверхности Земли она окажется через 2 с после начала падения? Сопротивлением воздуха пренебречь.', '5 м', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 22, 'С вертолёта, зависшего над Землёй на высоте 980 м, упал груз. Сколько времени он падал на поверхность Земли? Сопротивлением воздуха пренебречь.', '14 с', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 22, 'Стрелу выпустили из лука под углом к горизонту. На какую максимальную высоту поднимется стрела, если через 4 с после вылета её скорость была направлена горизонтально? Сопротивлением воздуха пренебречь.', '80 м', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 22, 'Стрела, выпущенная из лука под углом к горизонту, упала на Землю в 160 м от места выстрела. Чему была равна скорость стрелы через 2 с после выстрела, если в этот момент она была направлена горизонтально? Сопротивлением воздуха пренебречь.', '40 м/с', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 22, 'Верхнюю точку моста радиусом 50 м автобус проходит со скоростью 36 км/ч. Определите центростремительное ускорение автобуса.', '2 м/с²', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 22, 'Две шестерни, сцепленные друг с другом, вращаются вокруг неподвижных осей (см. рисунок). Большая шестерня радиусом 10 см делает 20 оборотов за 10 с, а частота обращения малой шестерни равна $5$ с$^{-1}$. Каков радиус меньшей шестерни?', '4 см', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 22, 'Наклонная плоскость пересекается с горизонтальной плоскостью по прямой $AB$. Угол между плоскостями $\alpha = 30°$. Маленькая шайба скользит вверх по наклонной плоскости из точки $A$ с начальной скоростью $v_0 = 2$ м/с, направленной под углом $\beta = 60°$ к прямой $AB$ (см. рисунок). Найдите максимальное расстояние, на которое шайба удалится от горизонтальной плоскости. Трением между шайбой и наклонной плоскостью пренебречь.', '0,15 м', NULL, 'число', 'demidova_2025');
INSERT INTO public.kb_tasks (folder_id, owner_id, exam, kim_number, text, answer, solution, answer_format, source_label) VALUES
(_drafts_folder_id, _egor_id, 'ege', 1, 'Расстояние между пунктами А и В равно 30 км. Из пункта А в направлении пункта В выехал мотоциклист со скоростью 50 км/ч. Одновременно из пункта В в том же направлении, что и мотоциклист, выезжает трактор со скоростью 20 км/ч. На каком расстоянии от пункта А мотоциклист догонит трактор?', '50 км', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'Начальная скорость движения тела равна 5 м/с. Сколько потребуется времени, чтобы увеличить его скорость в 3 раза при равноускоренном движении по прямой в одном направлении на пути в 20 м?', '2 с', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'Какой путь пройдёт тело за 2 с, двигаясь по прямой в одном направлении, если его скорость за это время увеличилась в 3 раза? Модуль ускорения тела равен 5 м/с².', '20 м', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'Мимо остановки на прямой улице с постоянной скоростью проезжает автобус. Через 5 с от остановки вдогонку отъезжает автомобиль, движущийся с ускорением 3 м/с², и догоняет автобус на расстоянии 150 м от остановки. Чему равна скорость автобуса?', '10 м/с', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 22, 'Мячик, брошенный с крыши дома почти вертикально вверх со скоростью 10 м/с, упал на Землю через 4 с после броска. С какой высоты был брошен мячик? Сопротивлением воздуха не учитывать.', '40 м', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 22, 'Небольшой камень, брошенный с ровной горизонтальной поверхности Земли под углом к горизонту, достиг максимальной высоты 5 м и упал обратно на Землю в 20 м от места броска. Чему равна минимальная скорость камня за время полёта?', '10 м/с', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'Два шкива, соединённые друг с другом ремнём, вращаются вокруг неподвижных осей (см. рисунок). Шкив радиусом 20 см делает 50 оборотов за 10 с. Сколько оборотов в минуту делает шкив радиусом 5 см? Ремень по шкивам не проскальзывает.', '1200 об/мин', NULL, 'число', 'demidova_2025'),
(_drafts_folder_id, _egor_id, 'ege', 1, 'Две шестерни, сцепленные друг с другом, вращаются вокруг неподвижных осей. Маленькая шестерня радиусом 10 см делает 50 оборотов за 10 с, а частота обращения большой шестерни равна $2$ с$^{-1}$. Каков радиус большой шестерни?', '25 см', NULL, 'число', 'demidova_2025');
